cd /tmp/sv-703a4b780b064121aff098c1bd5c7bd5/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json

with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): (requested, resolved)}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv and av:
        if bv[1] != av[1]:
            changes.append((proj, fw, pkg, bv[1], av[1], 'Aligned to highest version'))
        else:
            unchanged.append((proj, fw, pkg, av[1]))
    elif bv and not av:
        changes.append((proj, fw, pkg, bv[1], '-', 'Removed'))
    elif av and not bv:
        changes.append((proj, fw, pkg, '-', av[1], 'Added'))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<15} {'Framework':<10} {'Package':<45} {'Before':<10} {'After':<10} Status')
    for c in changes:
        print(f'{c[0]:<15} {c[1]:<10} {c[2]:<45} {c[3]:<10} {c[4]:<10} {c[5]}')
else:
    print('No changes')

print()
print('=== UNCHANGED ===')
print(f'{'Project':<15} {'Framework':<10} {'Package':<45} {'Version':<10}')
for u in unchanged:
    print(f'{u[0]:<15} {u[1]:<10} {u[2]:<45} {u[3]:<10}')
"

